    for j, v in enumerate(frame_top):
        if v != bg:
            marker_cols.setdefault(int(v), []).append(j + right_start)
    marker_rows = {}
    for r, v in enumerate(frame_left):
        if v != bg:
            marker_rows.setdefault(int(v), []).append(r)

    # Build output
    pred = np.zeros_like(inp)
    # Copy separator
    pred[:, sep_col] = inp[:, sep_col]
    # Copy frame borders
    pred[0, right_start:] = inp[0, right_start:]
    pred[H-1, right_start:] = inp[H-1, right_start:]
    pred[:, right_start] = inp[:, right_start]
    pred[:, W-1] = inp[:, W-1]

