    left_colors = sorted(set(left.flatten()) - {0})
    for color in left_colors:
        positions = np.argwhere(left == color)
        r_min, c_min = positions.min(axis=0)
        r_max, c_max = positions.max(axis=0)
        shape = left[r_min:r_max+1, c_min:c_max+1]
        center_r = (r_min + r_max) // 2
        center_c = (c_min + c_max) // 2

